117тЖТ                    <div className="mobile-navlink-icon-container">
118тЖТ                        {navLinks.map((link, index) => {
119тЖТ                            const isActive = link.path && location.pathname === link.path;
120тЖТ
121тЖТ                            return (
122тЖТ                                <div
123тЖТ                                    key={index}
124тЖТ                                    className="mobile-navlink-item"
125тЖТ                                    onClick={() => link.action(link.path)}
126тЖТ                                >
127тЖТ                                    <div className="mobile-navlink-icons">
128тЖТ                                        {link.icon(isActive)}
129тЖТ                                    </div>
130тЖТ                                    <p className={`mobile-navlink-label ${isActive ? 'mobile-navlink-label-active' : ''}`}>
131тЖТ                                        {link.label}
132тЖТ                                    </p>
133тЖТ                                    {isActive && <div className="mobile-navlink-active-dot" />}
134тЖТ                                </div>
135тЖТ                            );
136тЖТ                        })}
137тЖТ                    </div>
138тЖТ                </motion.div>
139тЖТ            )}
140тЖТ        </>
141тЖТ    );
142тЖТ};
143тЖТ
144тЖТexport default MobileNavlink;
