 13тЖТ    const [error, setError] = useState('');
 14тЖТ
 15тЖТ    const repostMutation = useRepostMutation(session);
 16тЖТ
 17тЖТ    const handleSubmit = () => {
 18тЖТ        if(repostMutation.isPending) return;
 19тЖТ        setError('');
 20тЖТ
 21тЖТ        repostMutation.mutate(
 22тЖТ            {
 23тЖТ                sourceJournalId: journal.id,
 24тЖТ                caption: caption.trim() || ''
 25тЖТ            },
 26тЖТ            {
 27тЖТ                onSuccess: () => {
 28тЖТ                    onClose('success');
 29тЖТ                },
 30тЖТ                onError: (err) => {
 31тЖТ                    setError(err?.message || 'Failed to repost');
 32тЖТ                }
 33тЖТ            }
 34тЖТ        );
 35тЖТ    };
 36тЖТ
 37тЖТ    return (
 38тЖТ        <AnimatePresence>
 39тЖТ            <motion.div
 40тЖТ                className="repost-overlay"
 41тЖТ                initial={{ opacity: 0 }}
 42тЖТ                animate={{ opacity: 1 }}
 43тЖТ                exit={{ opacity: 0 }}
 44тЖТ                transition={{ duration: 0.2 }}
 45тЖТ                onClick={() => onClose()}
 46тЖТ            >
 47тЖТ                <motion.div
 48тЖТ                    className="repost-modal"
 49тЖТ                    initial={{ opacity: 0, scale: 0.92, y: 20 }}
 50тЖТ                    animate={{ opacity: 1, scale: 1, y: 0 }}
 51тЖТ                    exit={{ opacity: 0, scale: 0.92, y: 20 }}
 52тЖТ                    transition={{ type: 'spring', stiffness: 400, damping: 30 }}
 53тЖТ                    onClick={(e) => e.stopPropagation()}
 54тЖТ                >
 55тЖТ                    <div className="repost-modal-header">
 56тЖТ                        <h3 className="repost-modal-title">Repost</h3>
 57тЖТ                        <button className="repost-modal-close" onClick={() => onClose()}>
 58тЖТ                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
 59тЖТ                                <path d="M18.3 5.71a1 1 0 0 0-1.42 0L12 10.59 7.12 5.71a1 1 0 1 0-1.42 1.42L10.59 12l-4.88 4.88a1 1 0 1 0 1.42 1.42L12 13.41l4.88 4.88a1 1 0 0 0 1.42-1.42L13.41 12l4.88-4.88a1 1 0 0 0 0-1.41Z"/>
 60тЖТ                            </svg>
 61тЖТ                        </button>
 62тЖТ                    </div>
 63тЖТ
 64тЖТ                    <div className="repost-original-preview">
 65тЖТ                        <div className="repost-original-author">
 66тЖТ                            <img
 67тЖТ                                className="repost-original-avatar"
 68тЖТ                                src={journal?.users?.image_url || '/assets/profile.jpg'}
 69тЖТ                                alt="author"
 70тЖТ                            />
 71тЖТ                            <span className="repost-original-name">{journal?.users?.name}</span>
 72тЖТ                            <VerifiedBadge badge={journal?.users?.badge} size={12} />
 73тЖТ                        </div>
 74тЖТ                        <p className="repost-original-title">{journal?.title?.length > 80 ? journal.title.substring(0, 80) + '...' : journal?.title}</p>
 75тЖТ                    </div>
 76тЖТ
 77тЖТ                    <div className="repost-caption-container">
 78тЖТ                        <textarea
 79тЖТ                            className="repost-caption-input"
 80тЖТ                            placeholder="Add your thoughts (optional)..."
 81тЖТ                            value={caption}
 82тЖТ                            onChange={(e) => {
 83тЖТ                                if(e.target.value.length <= CAPTION_MAX){
 84тЖТ                                    setCaption(e.target.value);
 85тЖТ                                }
 86тЖТ                            }}
 87тЖТ                            maxLength={CAPTION_MAX}
 88тЖТ                            rows={3}
