 91тЖТ                            {caption.length}/{CAPTION_MAX}
 92тЖТ                        </span>
 93тЖТ                    </div>
 94тЖТ
 95тЖТ                    {error && (
 96тЖТ                        <p className="repost-error">{error}</p>
 97тЖТ                    )}
 98тЖТ
 99тЖТ                    <div className="repost-modal-actions">
100тЖТ                        <button className="repost-cancel-btn" onClick={() => onClose()}>Cancel</button>

